  "inlineSchema": "// backend/prisma/schema.prisma\n// Run:  npx prisma migrate dev --name init\n//       npx prisma generate\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─────────────────────────────────────────────────────\n//  USERS\n// ─────────────────────────────────────────────────────\n\nenum Role {\n  STUDENT\n  PARENT\n  ADMIN\n}\n\nenum Plan {\n  FREE\n  BASIC\n  PREMIUM\n}\n\nmodel User {\n  id           String   @id @default(uuid())\n  email        String   @unique\n  passwordHash String\n  role         Role     @default(STUDENT)\n  plan         Plan     @default(FREE)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  // Student profile\n  username     String?   @unique\n  displayName  String?\n  avatarEmoji  String?   @default(\"🏃\")\n  age          Int?\n  xp           Int       @default(0)\n  coins        Int       @default(0)\n  level        Int       @default(1)\n  streakDays   Int       @default(0)\n  lastActiveAt DateTime?\n\n  // Parent link\n  parentId String?\n  parent   User?   @relation(\"ParentChildren\", fields: [parentId], references: [id])\n  children User[]  @relation(\"ParentChildren\")\n\n  // Relations\n  progress     Progress[]\n  payments     Payment[]\n  earnedBadges UserBadge[]\n\n  @@map(\"users\")\n}\n\n// ─────────────────────────────────────────────────────\n//  COURSES\n// ─────────────────────────────────────────────────────\n\nmodel Course {\n  id           String   @id @default(uuid())\n  title        String\n  emoji        String\n  description  String?\n  color        String   @default(\"#00C8E8\")\n  subject      String // \"HTML/CSS\", \"Python\", etc.\n  ageGroup     String   @default(\"5-13\")\n  order        Int      @default(0) // display order\n  isPublished  Boolean  @default(false)\n  isLocked     Boolean  @default(true)\n  unlocksAfter String? // courseId that must be completed first\n  totalXp      Int      @default(0)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  sessions Session[]\n  progress Progress[]\n\n  @@map(\"courses\")\n}\n\n// ─────────────────────────────────────────────────────\n//  SESSIONS  (individual lessons within a course)\n// ─────────────────────────────────────────────────────\n\nenum SessionType {\n  VIDEO // Video + optional IDE\n  DOCUMENT // Reading / notes\n  QUIZ // Multiple-choice quiz\n  CODE // Code challenge only\n  BOSS // Final boss level\n}\n\nmodel Session {\n  id       String @id @default(uuid())\n  courseId String\n  course   Course @relation(fields: [courseId], references: [id], onDelete: Cascade)\n\n  title       String\n  type        SessionType\n  order       Int         @default(0)\n  isPublished Boolean     @default(false)\n\n  // XP & gamification\n  xpReward     Int @default(50)\n  coinsReward  Int @default(5)\n  durationMins Int @default(5)\n\n  // Video session fields\n  videoUrl    String? // Bunny.net embed URL\n  videoThumb  String? // Thumbnail image URL\n  hasIde      Boolean @default(false)\n  missionText String? // Instructions shown next to video\n\n  // Document session fields\n  docContent String? // Markdown content\n\n  // Code challenge fields\n  starterCode  String?\n  solutionCode String?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  quizQuestions QuizQuestion[]\n  progress      Progress[]\n\n  @@map(\"sessions\")\n}\n\n// ─────────────────────────────────────────────────────\n//  QUIZ QUESTIONS\n// ─────────────────────────────────────────────────────\n\nmodel QuizQuestion {\n  id        String  @id @default(uuid())\n  sessionId String\n  session   Session @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  question      String\n  emoji         String?\n  optionA       String\n  optionB       String\n  optionC       String\n  optionD       String\n  correctAnswer String // \"A\", \"B\", \"C\", or \"D\"\n  explanation   String?\n  order         Int     @default(0)\n\n  createdAt DateTime @default(now())\n\n  @@map(\"quiz_questions\")\n}\n\n// ─────────────────────────────────────────────────────\n//  PROGRESS\n// ─────────────────────────────────────────────────────\n\nmodel Progress {\n  id        String  @id @default(uuid())\n  userId    String\n  user      User    @relation(fields: [userId], references: [id], onDelete: Cascade)\n  courseId  String\n  course    Course  @relation(fields: [courseId], references: [id], onDelete: Cascade)\n  sessionId String\n  session   Session @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  completed   Boolean   @default(false)\n  stars       Int       @default(0) // 0-3\n  xpEarned    Int       @default(0)\n  coinsEarned Int       @default(0)\n  completedAt DateTime?\n\n  @@unique([userId, sessionId])\n  @@map(\"progress\")\n}\n\n// ─────────────────────────────────────────────────────\n//  BADGES\n// ─────────────────────────────────────────────────────\n\nmodel Badge {\n  id          String @id @default(uuid())\n  emoji       String\n  name        String\n  description String\n  condition   String // e.g. \"complete_first_lesson\", \"7_day_streak\"\n\n  earnedBy UserBadge[]\n\n  @@map(\"badges\")\n}\n\nmodel UserBadge {\n  id       String   @id @default(uuid())\n  userId   String\n  user     User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  badgeId  String\n  badge    Badge    @relation(fields: [badgeId], references: [id], onDelete: Cascade)\n  earnedAt DateTime @default(now())\n\n  @@unique([userId, badgeId])\n  @@map(\"user_badges\")\n}\n\n// ─────────────────────────────────────────────────────\n//  PAYMENTS\n// ─────────────────────────────────────────────────────\n\nenum PaymentStatus {\n  PENDING\n  PAID\n  FAILED\n  REFUNDED\n}\n\nmodel Payment {\n  id     String @id @default(uuid())\n  userId String\n  user   User   @relation(fields: [userId], references: [id])\n\n  razorpayOrderId   String? @unique\n  razorpayPaymentId String? @unique\n  razorpaySignature String?\n\n  plan     Plan\n  amount   Int // in paise (₹299 = 29900)\n  currency String        @default(\"INR\")\n  status   PaymentStatus @default(PENDING)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"payments\")\n}\n",
